  display: 'block', fontSize: '12px', fontWeight: '700', color: '#4a5568',
  letterSpacing: '0.5px', textTransform: 'uppercase', marginBottom: '7px',
  fontFamily: "'Outfit', sans-serif",
};
const fieldErrorStyle = {
  margin: '5px 0 0', fontSize: '12px', color: '#e74c3c', fontFamily: "'Outfit', sans-serif",
};
const inputWrapperStyle = {
  position: 'relative', display: 'flex', alignItems: 'center',
};
const iconLeftStyle = {
  position: 'absolute', left: '14px', color: '#8a9bb0',
  display: 'flex', alignItems: 'center', pointerEvents: 'none', zIndex: 1,
};
const toggleBtnStyle = {
  position: 'absolute', right: '12px', background: 'none', border: 'none',
  cursor: 'pointer', color: '#8a9bb0', display: 'flex', alignItems: 'center',
  padding: '4px', borderRadius: '6px',
};
